/**
 * Jugend variant uses Ambrosia font.
 * License: OFL (SIL Open Font License)
 * https://fontlibrary.org/en/font/ambrosia
 */
import * as React from "react"

import { ambrosia } from "@/lib/fonts/ambrosia"
import { cn } from "@/lib/utils"

type HeadingLevel = 1 | 2 | 3 | 4 | 5 | 6

const headingTags = {
  1: "h1",
  2: "h2",
  3: "h3",
  4: "h4",
  5: "h5",
  6: "h6",
} as const satisfies Record<HeadingLevel, `h${HeadingLevel}`>

type JugendHeadingProps = {
  level: HeadingLevel
} & React.ComponentPropsWithoutRef<"h1">

function JugendHeading({ level, className, ...props }: JugendHeadingProps) {
  const Tag = headingTags[level]

  return (
    <Tag
      data-slot="heading"
      data-level={level}
      data-variant="jugend"
      className={cn(ambrosia.className, "tracking-wide", className)}
      {...props}
    />
  )
}

export { JugendHeading, type JugendHeadingProps, type HeadingLevel }

import { cva, type VariantProps } from "class-variance-authority"
import dynamic from "next/dynamic"
import * as React from "react"

import { cn } from "@/lib/utils"

import type { HeadingLevel } from "./heading-jugend"

const JugendHeading = dynamic(() =>
  import("./heading-jugend").then((mod) => ({ default: mod.JugendHeading }))
)

const headingVariants = cva("", {
  variants: {
    variant: {
      default: "",
      jugend: "",
    },
  },
  defaultVariants: {
    variant: "default",
  },
})

const headingTags = {
  1: "h1",
  2: "h2",
  3: "h3",
  4: "h4",
  5: "h5",
  6: "h6",
} as const satisfies Record<HeadingLevel, `h${HeadingLevel}`>

type HeadingProps = {
  level: HeadingLevel
} & VariantProps<typeof headingVariants> &
  React.ComponentPropsWithoutRef<"h1">

function Heading({
  level,
  variant = "default",
  className,
  ...props
}: HeadingProps) {
  if (variant === "jugend") {
    return (
      <JugendHeading level={level} className={className} {...props} />
    )
  }

  const Tag = headingTags[level]

  return (
    <Tag
      data-slot="heading"
      data-level={level}
      data-variant={variant}
      className={cn(headingVariants({ variant }), className)}
      {...props}
    />
  )
}

export { Heading, headingVariants, type HeadingLevel, type HeadingProps }

import localFont from "next/font/local"

export const ambrosia = localFont({
  src: [
    {
      path: "../../assets/fonts/ambrosia/ambrosia-medium.otf",
      weight: "400",
      style: "normal",
    },
  ],
  variable: "--font-ambrosia",
  display: "swap",
})
